import React from "react";

const AdminProducts = () => {
  const products = [
    { id: 1, name: "T-Shirt", price: "RM 50" },
    { id: 2, name: "Shoes", price: "RM 120" },
  ];

  return (
    <>
      <h1>Products</h1>

      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Product</th>
            <th>Price</th>
          </tr>
        </thead>

        <tbody>
          {products.map((p) => (
            <tr key={p.id}>
              <td>{p.id}</td>
              <td>{p.name}</td>
              <td>{p.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );
};

export default AdminProducts;
